mapper.select:
SELECT r.id, r.patient_id, p.patient_name, p.gender, p.age, p.phone,
       r.doctor_id, d.doctor_name, d.title,
       r.dept_id, dept.dept_name,
       r.reg_type, r.reg_fee, r.reg_time, r.status
FROM registration r
LEFT JOIN patient p ON r.patient_id = p.id
LEFT JOIN doctor d ON r.doctor_id = d.id
LEFT JOIN department dept ON r.dept_id = dept.id

    AND r.patient_id = #{patientId}
    AND r.doctor_id = #{doctorId}
    AND r.status = #{status}
    AND p.patient_name LIKE CONCAT('%', #{patientName}, '%')
    AND r.dept_id = #{deptId}

ORDER BY r.reg_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM registration r
LEFT JOIN patient p ON r.patient_id = p.id

    AND r.patient_id = #{patientId}
    AND r.doctor_id = #{doctorId}
    AND r.status = #{status}
    AND p.patient_name LIKE CONCAT('%', #{patientName}, '%')
    AND r.dept_id = #{deptId}
